/* -------------------------------------------------------------------------- */
/*                                ACTION TYPES                                */
/* -------------------------------------------------------------------------- */
const FILTERS_StatusChanged = 'filters/statusFilterChanged';
const FILTERS_ColorChanged = 'filters/colorFilterChanged';
const FILTERS_TagsChanged = 'filters/tagsFilterChanged';

/* -------------------------------------------------------------------------- */
/*                                 INIT STATES                                */
/* -------------------------------------------------------------------------- */
/**
 * @typedef {{
 * colors: ["purple"?, "red"?, "green"?, "brown"?, "yellow"?, "blue"?, "pink"?],
 * status: "Active" | "All" | "Completed", 
 * tags: string[]
 * }} FilterState
 */
/** @type {FilterState} */
const initFiltersState = {
    colors: [],
    status: "Active",
    tags: []
}

/* -------------------------------------------------------------------------- */
/*                                  REDUCERS                                  */
/* -------------------------------------------------------------------------- */
function filtersReducer(state = initFiltersState, action) {
    switch (action.type) {
        case FILTERS_StatusChanged: return { ...state, status: action.payload };
        case FILTERS_ColorChanged: {
            const arr = new Set(state.colors);
            if (action.payload.changeType === "add") 
                arr.add(action.payload.color);
            else if (action.payload.changeType === "delete") 
                arr.delete(action.payload.color);
            return {
                ...state,
                colors: [...arr]
            }
        }
        case FILTERS_TagsChanged: {
            const arr = new Set(state.tags);
            if (action.payload.changeType === "add") 
                arr.add(action.payload.tag);
            else if (action.payload.changeType === "delete") 
                arr.delete(action.payload.tag);
            return {
                ...state,
                tags: [...arr]
            }
        }
        default: return state;
    }
}

export {
    filtersReducer
}
